		end
		if methodName == "ToHashSet" then
			self._needsRuntime = true
			return "__rt.toHashSet(" .. obj .. ")"
		end
		if methodName == "AppendFormat" then
			return obj .. " = " .. obj .. " .. string.format(" .. args .. ")"
		end
		if methodName == "Insert" then
			local sbInsertVarType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
			if sbInsertVarType ~= nil and sbInsertVarType == "StringBuilder" and #inv.Arguments == 2 then
				local idx: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local text: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return obj .. " = string.sub(" .. obj .. ", 1, " .. idx .. ") .. " .. text .. " .. string.sub(" .. obj .. ", " .. idx .. " + 1)"
			end
		end
		if methodName == "Remove" then
			local sbRemoveVarType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
			if sbRemoveVarType ~= nil and sbRemoveVarType == "StringBuilder" and #inv.Arguments == 2 then
				local startIdx: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local removeLen: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return obj .. " = string.sub(" .. obj .. ", 1, " .. startIdx .. ") .. string.sub(" .. obj .. ", " .. startIdx .. " + " .. removeLen .. " + 1)"
			end
			if sbRemoveVarType ~= nil and SimpleEmitter.IsStringType(self, sbRemoveVarType) then
				if #inv.Arguments == 1 then
					local startIdx: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
					return "string.sub(" .. obj .. ", 1, " .. startIdx .. ")"
				end
				if #inv.Arguments == 2 then
					local startIdx: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
					local removeLen: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
					return "string.sub(" .. obj .. ", 1, " .. startIdx .. ") .. string.sub(" .. obj .. ", " .. startIdx .. " + " .. removeLen .. " + 1)"
				end
			end
		end
		if methodName == "Replace" then
			local sbReplaceVarType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
			if sbReplaceVarType ~= nil and sbReplaceVarType == "StringBuilder" and #inv.Arguments == 2 then
				local oldVal: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local newVal: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return obj .. " = string.gsub(" .. obj .. ", " .. oldVal .. ", " .. newVal .. ")"
			end
			if sbReplaceVarType ~= nil and SimpleEmitter.IsStringType(self, sbReplaceVarType) and #inv.Arguments == 2 then
				local oldVal: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local newVal: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return "string.gsub(" .. obj .. ", " .. oldVal .. ", " .. newVal .. ")"
			end
		end
		if methodName == "Insert" then
			local strInsertVarType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
			if strInsertVarType ~= nil and SimpleEmitter.IsStringType(self, strInsertVarType) and #inv.Arguments == 2 then
				local idx: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local text: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return "string.sub(" .. obj .. ", 1, " .. idx .. ") .. " .. text .. " .. string.sub(" .. obj .. ", " .. idx .. " + 1)"
			end
		end
		if methodName == "Substring" then
			if #inv.Arguments == 1 then
				return "string.sub(" .. obj .. ", " .. args .. " + 1)"
			end
			if #inv.Arguments == 2 then
				local start: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local len: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return "string.sub(" .. obj .. ", " .. start .. " + 1, " .. start .. " + " .. len .. ")"
			end
		end
		if methodName == "IndexOf" then
			local findArg: string = args
			if #inv.Arguments == 1 and inv.Arguments[1].Kind == 8752 then
				findArg = "string.char(" .. args .. ")"
			end
			return "(string.find(" .. obj .. ", " .. findArg .. ", 1, true) or 0) - 1"
		end
		if methodName == "StartsWith" then
			return "string.sub(" .. obj .. ", 1, #" .. args .. ") == " .. args
		end
		if methodName == "EndsWith" then
			return "string.sub(" .. obj .. ", -#" .. args .. ") == " .. args
		end
		if methodName == "Trim" then
			return "string.match(" .. obj .. ", \"^%s*(.-)%s*$\")"
		end
		if methodName == "ToLower" then
			return "string.lower(" .. obj .. ")"
		end
		if methodName == "ToUpper" then
			return "string.upper(" .. obj .. ")"
		end
		if methodName == "Replace" then
			return "string.gsub(" .. obj .. ", " .. args .. ")"
		end
		if methodName == "Split" then
			if #inv.Arguments == 1 then
				return "string.split(" .. obj .. ", " .. args .. ")"
			end
			self._needsRuntime = true
			return "__rt.stringSplit(" .. obj .. ", " .. args .. ")"
		end
		if methodName == "LastIndexOf" then
			self._needsRuntime = true
			return "__rt.lastIndexOf(" .. obj .. ", " .. args .. ")"
		end
		if methodName == "PadLeft" then
			if #inv.Arguments == 1 then
				local totalWidth: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				return "string.rep(\" \", " .. totalWidth .. " - #" .. obj .. ") .. " .. obj
			end
			if #inv.Arguments == 2 then
				local totalWidth: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local padChar: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return "string.rep(string.char(" .. padChar .. "), " .. totalWidth .. " - #" .. obj .. ") .. " .. obj
			end
		end
		if methodName == "PadRight" then
			if #inv.Arguments == 1 then
				local totalWidth: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				return obj .. " .. string.rep(\" \", " .. totalWidth .. " - #" .. obj .. ")"
			end
			if #inv.Arguments == 2 then
				local totalWidth: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
				local padChar: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
				return obj .. " .. string.rep(string.char(" .. padChar .. "), " .. totalWidth .. " - #" .. obj .. ")"
			end
		end
		if methodName == "TrimStart" then
			return "string.match(" .. obj .. ", \"^%s*(.*)\")"
		end
		if methodName == "TrimEnd" then
			return "string.match(" .. obj .. ", \"(.-)%s*$\")"
		end
	end
	if inv.Expression.Kind == 8616 then
		local preCheckId: IdentifierNameSyntax = inv.Expression
		if preCheckId.Identifier.Text == "nameof" and #inv.Arguments == 1 then
			local nameofArg: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
			local dotPos: number = #nameofArg - 1
			while dotPos >= 0 and nameofArg[dotPos + 1] ~= string.byte(".", 1) do
				dotPos = dotPos - 1
			end
			if dotPos >= 0 then
				return "\"" .. string.sub(nameofArg, dotPos + 1 + 1) .. "\""
			end
			return "\"" .. nameofArg .. "\""
		end
	end
	if inv.Expression.Kind == 8616 then
		local calleeId: IdentifierNameSyntax = inv.Expression
		local methodName: string = calleeId.Identifier.Text
		if not self._isStaticContext and #self._currentClassName > 0 and SimpleEmitter.IsInstanceMethod(self, methodName) then
			if #args > 0 then
				return self._currentClassName .. "." .. methodName .. "(self, " .. args .. ")"
			end
			return self._currentClassName .. "." .. methodName .. "(self)"
		end
		if #self._currentClassName > 0 and SimpleEmitter.IsStaticMethod(self, methodName) then
			return self._currentClassName .. "." .. methodName .. "(" .. args .. ")"
		end
	end
	local callee: string = SimpleEmitter.EmitExpression(self, inv.Expression)
	return callee .. "(" .. args .. ")"
end

function SimpleEmitter.EmitObjectCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local obj: ObjectCreationExpressionSyntax = expr
	local args: string = ""
	for i = 0, #obj.Arguments - 1 do
		if i > 0 then
			args = args .. ", "
		end
		args = args .. SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
	end
	local typeName: string = obj.TypeName
	if typeName == "StringBuilder" then
		return "\"\""
	end
	if #typeName > 5 and string.sub(typeName, 0 + 1, 0 + 5) == "List<" then
		return "{}"
	end
	if #typeName > 11 and string.sub(typeName, 0 + 1, 0 + 11) == "Dictionary<" then
		return "{}"
	end
	if #typeName > 8 and string.sub(typeName, 0 + 1, 0 + 8) == "HashSet<" then
		return "{}"
	end
	if #typeName > 6 and string.sub(typeName, 0 + 1, 0 + 6) == "Queue<" then
		return "{}"
	end
	if #typeName > 6 and string.sub(typeName, 0 + 1, 0 + 6) == "Stack<" then
		return "{}"
	end
	if typeName == "Random" then
		if #obj.Arguments > 0 then
			return "Random.new(" .. args .. ")"
		end
		return "Random.new()"
	end
	if typeName == "Stopwatch" then
		self._needsRuntime = true
		return "__rt.Stopwatch.StartNew()"
	end
	if typeName == "CancellationTokenSource" then
		self._needsRuntime = true
		return "__rt.CancellationToken.new()"
	end
	if typeName == "Exception" or typeName == "InvalidOperationException" or typeName == "ArgumentException" or typeName == "ArgumentNullException" or typeName == "NotImplementedException" or typeName == "NotSupportedException" or typeName == "IndexOutOfRangeException" or typeName == "OverflowException" then
		if #obj.Arguments > 0 then
			return SimpleEmitter.EmitExpression(self, obj.Arguments[1])
		end
		return "\"" .. typeName .. "\""
	end
	if #obj.Initializers > 0 then
		local iife: string = "(function() local __obj = " .. typeName .. ".new(" .. args .. "); "
		for i = 0, #obj.Initializers - 1 do
			local fieldName: string = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Left)
			local fieldVal: string = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Right)
			iife = iife .. "__obj." .. fieldName .. " = " .. fieldVal .. "; "
		end
		iife = iife .. "return __obj end)()"
		return iife
	end
	if #typeName > 2 and string.sub(typeName, #typeName - 2 + 1) == "[]" then
		if #args == 0 then
			return "{}"
		end
		local elems: string = ""
		for i = 0, #obj.Arguments - 1 do
			if i > 0 then
				elems = elems .. ", "
			end
			elems = elems .. SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
		end
		return "{ " .. elems .. " }"
	end
	return typeName .. ".new(" .. args .. ")"
end

function SimpleEmitter.EmitArrayCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local arr: ArrayCreationExpressionSyntax = expr
	if arr.SizeExpression ~= nil then
		local size: string = SimpleEmitter.EmitExpression(self, arr.SizeExpression)
		return "table.create(" .. size .. ")"
	end
	return "{}"
end

function SimpleEmitter.GetVariableType(self: SimpleEmitter, name: string): string
	for i = 0, self._paramCount - 1 do
		if self._paramNames[i + 1] == name then
			return self._paramTypes[i + 1]
		end
	end
	for i = 0, self._localCount - 1 do
		if self._localNames[i + 1] == name then
			return self._localTypes[i + 1]
		end
	end
	return nil
end

function SimpleEmitter.IsStringType(self: SimpleEmitter, typeName: string): boolean
	if typeName == nil then
		return false
	end
	if typeName == "string" then
		return true
	end
	if typeName == "String" then
		return true
	end
	return false
end

function SimpleEmitter.TransformInterpolationExpr(self: SimpleEmitter, csExpr: string): string
	local trimmed: string = csExpr
	while #trimmed > 0 and string.byte(trimmed, 1) == string.byte(" ", 1) do
		trimmed = string.sub(trimmed, 1 + 1)
	end
	while #trimmed > 0 and string.byte(trimmed, #trimmed - 1 + 1) == string.byte(" ", 1) do
		trimmed = string.sub(trimmed, 0 + 1, 0 + #trimmed - 1)
	end
	if #trimmed == 0 then
		return csExpr
	end
	if #trimmed > 7 and string.sub(trimmed, #trimmed - 7 + 1) == ".Length" then
		local obj: string = string.sub(trimmed, 0 + 1, 0 + #trimmed - 7)
		return "#" .. obj
	end
	if #trimmed > 6 and string.sub(trimmed, #trimmed - 6 + 1) == ".Count" then
		local obj: string = string.sub(trimmed, 0 + 1, 0 + #trimmed - 6)
		return "#" .. obj
	end
	if #trimmed > 11 and string.sub(trimmed, #trimmed - 11 + 1) == ".ToString()" then
		local obj: string = string.sub(trimmed, 0 + 1, 0 + #trimmed - 11)
		return "tostring(" .. obj .. ")"
	end
	if #trimmed > 10 and string.sub(trimmed, #trimmed - 10 + 1) == ".ToLower()" then
		local obj: string = string.sub(trimmed, 0 + 1, 0 + #trimmed - 10)
		return "string.lower(" .. obj .. ")"
	end
	if #trimmed > 10 and string.sub(trimmed, #trimmed - 10 + 1) == ".ToUpper()" then
		local obj: string = string.sub(trimmed, 0 + 1, 0 + #trimmed - 10)
		return "string.upper(" .. obj .. ")"
	end
	if #trimmed > 7 and string.sub(trimmed, #trimmed - 7 + 1) == ".Trim()" then
		local obj: string = string.sub(trimmed, 0 + 1, 0 + #trimmed - 7)
		return "string.match(" .. obj .. ", \"^%s*(.-)%s*$\")"
	end
	return trimmed
end

function SimpleEmitter.GetIdentifierName(self: SimpleEmitter, expr: ExpressionSyntax): string
	if expr.Kind == 8616 then
		local id: IdentifierNameSyntax = expr
		return id.Identifier.Text
	end
	return nil
end

function SimpleEmitter.GetFieldType(self: SimpleEmitter, fieldName: string): string
	for i = 0, self._fieldCount - 1 do
		if self._fieldNames[i + 1] == fieldName then
			return self._fieldTypes[i + 1]
		end
	end
	return nil
end

function SimpleEmitter.IsStringExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8616 then
		local id: IdentifierNameSyntax = expr
		local name: string = id.Identifier.Text
		local varType: string = SimpleEmitter.GetVariableType(self, name)
		if varType ~= nil then
			return SimpleEmitter.IsStringType(self, varType)
		end
		if not self._isStaticContext then
			local fieldType: string = SimpleEmitter.GetFieldType(self, name)
			if fieldType ~= nil then
				return SimpleEmitter.IsStringType(self, fieldType)
			end
		end
	end
	if expr.Kind == 8689 then
		local ma: MemberAccessExpressionSyntax = expr
		if ma.Expression.Kind == 8616 then
			local leftId: IdentifierNameSyntax = ma.Expression
			local leftName: string = leftId.Identifier.Text
			if leftName == "this" or leftName == "self" then
				local fieldType: string = SimpleEmitter.GetFieldType(self, ma.Name.Text)
				if fieldType ~= nil then
					return SimpleEmitter.IsStringType(self, fieldType)
				end
			end
		end
	end
	return false
end

function SimpleEmitter.EmitElementAccess(self: SimpleEmitter, expr: ExpressionSyntax): string
	local ea: ElementAccessExpressionSyntax = expr
	local obj: string = SimpleEmitter.EmitExpression(self, ea.Expression)
	local index: string = SimpleEmitter.EmitExpression(self, ea.Index)
	local isStringIndex: boolean = SimpleEmitter.IsStringExpression(self, ea.Expression)
	if isStringIndex then
		if ea.Index.Kind == 8750 then
			local lit: LiteralExpressionSyntax = ea.Index
			local numText: string = lit.Token.Text
			local numVal: number = 0
			local isSimple: boolean = true
			for i = 0, #numText - 1 do
				local c: number = string.byte(numText, i + 1)
				if c >= string.byte("0", 1) and c <= string.byte("9", 1) then
					numVal = numVal * 10 + (c - string.byte("0", 1))
				else
					isSimple = false
				end
			end
			if isSimple then
				return "string.byte(" .. obj .. ", " .. SimpleEmitter.IntToString(self, numVal + 1) .. ")"
			end
		end
		return "string.byte(" .. obj .. ", " .. index .. " + 1)"
	end
	if ea.Index.Kind == 8750 then
		local lit: LiteralExpressionSyntax = ea.Index
		local numText: string = lit.Token.Text
		local numVal: number = 0
		local isSimple: boolean = true
		for i = 0, #numText - 1 do
			local c: number = string.byte(numText, i + 1)
			if c >= string.byte("0", 1) and c <= string.byte("9", 1) then
				numVal = numVal * 10 + (c - string.byte("0", 1))
			else
				isSimple = false
			end
		end
		if isSimple then
			return obj .. "[" .. SimpleEmitter.IntToString(self, numVal + 1) .. "]"
		end
	end
	return obj .. "[" .. index .. " + 1]"
end

function SimpleEmitter.EmitLambda(self: SimpleEmitter, expr: ExpressionSyntax): string
	local lam: LambdaExpressionSyntax = expr
	local parms: string = ""
	for i = 0, #lam.ParameterNames - 1 do
		if i > 0 then
			parms = parms .. ", "
		end
		parms = parms .. lam.ParameterNames[i + 1]
	end
	if lam.ExpressionBody ~= nil then
		return "function(" .. parms .. ") return " .. SimpleEmitter.EmitExpression(self, lam.ExpressionBody) .. " end"
	end
	if lam.BlockBody ~= nil then
		local savedOutput: string = self._output
		local savedIndent: number = self._indent
		self._output = ""
		self._indent = 0
		SimpleEmitter.EmitBlockBody(self, lam.BlockBody)
		local body: string = self._output
		self._output = savedOutput
		self._indent = savedIndent
		if #body > 0 and string.byte(body, #body - 1 + 1) == 10 then
			body = string.sub(body, 0 + 1, 0 + #body - 1)
		end
		return "function(" .. parms .. ")\n" .. body .. "\nend"
	end
	return "function(" .. parms .. ") end"
end

function SimpleEmitter.EmitSwitchExpression(self: SimpleEmitter, expr: ExpressionSyntax): string
	local sw: SwitchExpressionSyntax = expr
	local govExpr: string = SimpleEmitter.EmitExpression(self, sw.GoverningExpression)
	local result: string = ""
	for i = 0, #sw.Arms - 1 do
		local arm: SwitchExpressionArmSyntax = sw.Arms[i + 1]
		local armExpr: string = SimpleEmitter.EmitExpression(self, arm.Expression)
		if arm.Pattern == nil then
			if #result == 0 then
				result = armExpr
			else
				result = result .. " else " .. armExpr
			end
		else
			local patternExpr: string = SimpleEmitter.EmitExpression(self, arm.Pattern)
			if #result == 0 then
				result = "if " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
			else
				result = result .. " elseif " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
			end
		end
	end
	return result
end

function SimpleEmitter.IntToString(self: SimpleEmitter, value: number): string
	if value == 0 then
		return "0"
	end
	local negative: boolean = false
	if value < 0 then
		negative = true
		value = -value
	end
	local result: string = ""
	local n: number = value
	while n > 0 do
		local digit: number = n % 10
		local c: number = (string.byte("0", 1) + digit)
		result = string.char(c) .. result
		n = n // 10
	end
	if negative then
		result = "-" .. result
	end
	return result
end


return { SimpleEmitter = SimpleEmitter }
